content:
FOR doc IN documents
  LET classes = (
    FOR cls, e IN 1..1 INBOUND doc extracted_from
      RETURN { label: cls.label, uri: cls.uri, confidence: cls.confidence, ontology_id: cls.ontology_id }
  )
  FILTER LENGTH(classes) > 0
  RETURN {
    document: doc.filename,
    doc_key: doc._key,
    status: doc.status,
    class_count: LENGTH(classes),
    classes: classes
  }

